import{_ as e,o as a,c as r,U as t}from"./chunks/framework.82e57da9.js";const d=JSON.parse('{"title":"AI等科技资讯","description":"","frontmatter":{},"headers":[],"relativePath":"Document/AI项目的资讯和热门开源项目/AI等科技资讯.md","filePath":"Document/AI项目的资讯和热门开源项目/AI等科技资讯.md","lastUpdated":1690701750000}'),o={name:"Document/AI项目的资讯和热门开源项目/AI等科技资讯.md"},l=t('<h1 id="ai等科技资讯" tabindex="-1">AI等科技资讯 <a class="header-anchor" href="#ai等科技资讯" aria-label="Permalink to &quot;AI等科技资讯&quot;">​</a></h1><h2 id="新闻话题" tabindex="-1">新闻话题 <a class="header-anchor" href="#新闻话题" aria-label="Permalink to &quot;新闻话题&quot;">​</a></h2><ul><li><a href="https://www.zhihu.com/question/585294957" target="_blank" rel="noreferrer">ChatGPT 爆火带动全新职业提示工程师，提示工程有多重要？未来该职业走向如何？</a></li><li><a href="https://mp.weixin.qq.com/s/TQTjLvmRNp3fuBzDmeatwQ" target="_blank" rel="noreferrer">重磅！Open AI开放ChatGPT模型API，“全民AIGC大时代”要来了！</a></li><li><a href="https://www.zhihu.com/question/582326598" target="_blank" rel="noreferrer">ChatGPT 这个风口，普通人怎么抓住？</a></li><li><a href="https://www.zhihu.com/question/570729170" target="_blank" rel="noreferrer">ChatGPT 有哪些神奇的使用方式？</a></li><li><a href="https://mp.weixin.qq.com/s/yo47lOtUGMMtOBPT4XqqpA" target="_blank" rel="noreferrer">微软德国首席技术官 Andreas Braun 表示，GPT-4 将于下周推出</a></li><li><a href="https://m.weibo.cn/status/4870616702788642?sudaref=hf0y97ff1r.feishu.cn" target="_blank" rel="noreferrer">香港大学宣布禁用ChatGPT</a></li><li><a href="https://www.zhihu.com/question/585757225?utm_campaign=Sharon&amp;utm_medium=social&amp;utm_oi=792817096856842240&amp;utm_psn=1612465296727666688&amp;utm_source=wechat_session&amp;utm_content=group3_supplementQuestions" target="_blank" rel="noreferrer">周鸿祎称 ChatGPT 可能两三年内就会产生自我意识威胁人类， ChatGPT 存在哪些安全问题？</a></li><li><a href="https://www.zhihu.com/question/583588366" target="_blank" rel="noreferrer">微软 ChatGPT 版 Bing 上线了，使用体验如何？符合你的需求吗？</a></li><li><a href="https://www.zhihu.com/question/570062224" target="_blank" rel="noreferrer">如何评价 ChatGPT ？会取代搜索引擎吗？</a></li><li><a href="https://m.163.com/tech/article/HVF0CG7A00097U7T.html?spss=adap_pc" target="_blank" rel="noreferrer">OpenAI CEO:将发布工具让用户定制AIGC系统</a></li></ul><h2 id="网易有道首推教育大模型「子曰」-6项应用可在线体验" tabindex="-1">网易有道首推教育大模型「子曰」，6项应用可在线体验 <a class="header-anchor" href="#网易有道首推教育大模型「子曰」-6项应用可在线体验" aria-label="Permalink to &quot;网易有道首推教育大模型「子曰」，6项应用可在线体验&quot;">​</a></h2><p>论文速读：<a href="https://read.youdao.com/" target="_blank" rel="noreferrer">read.youdao.com/</a></p><blockquote><p>其他功能试玩地址：<a href="https://aicenter.youdao.com/" target="_blank" rel="noreferrer">aicenter.youdao.com/</a></p></blockquote><p>7月26日，网易有道举办了「powered by 子曰」教育大模型应用成果发布会，重磅推出了国内首个教育领域的垂直大模型「子曰」，作为基座模型支持诸多下游任务，向所有下游场景提供语义理解、知识表达等基础能力。</p><p>基于此，<strong>有道研发团队在「子曰」大模型的基础上，为不同学习场景设计了定制化的模型，研发了六大创新应用</strong>：</p><blockquote><ul><li>LLM翻译</li><li>虚拟人口语教练</li><li>AI作文指导</li><li>语法精讲</li><li>AIBox</li><li>文档问答</li></ul></blockquote><h2 id="小红书上线ai功能「此刻」-涂鸦和文生图能力非常亮眼" tabindex="-1">小红书上线AI功能「此刻」，涂鸦和文生图能力非常亮眼 <a class="header-anchor" href="#小红书上线ai功能「此刻」-涂鸦和文生图能力非常亮眼" aria-label="Permalink to &quot;小红书上线AI功能「此刻」，涂鸦和文生图能力非常亮眼&quot;">​</a></h2><p><a href="https://mp.weixin.qq.com/s/0OlMR1wd5i02RqTgfPaAuQ" target="_blank" rel="noreferrer">小红书可以发纯文字笔记了｜红薯唠家常 (qq.com)</a></p><p>7月25日，小红书宣布推出新功能「此刻」。用户直接输入文字，算法会根据输入的文本内容生成相应的图片，有记事本、聊感悟、想吐槽三种图片格式。此外，用户也可以在画板上手绘涂鸦，并使用AI技术对涂鸦进行美化后发布。</p><p>这一功能基于AIGC技术开发，目前已经在最新版本中全量上线，供所有用户使用。<strong>只需要输入纯文字或者绘制简笔画，就可以轻松获取美化图片、一键发布啦！</strong></p><h2 id="山东能源与华为联合发布「盘古矿山大模型」-首个能源行业商业大模型" tabindex="-1">山东能源与华为联合发布「盘古矿山大模型」，首个能源行业商业大模型 <a class="header-anchor" href="#山东能源与华为联合发布「盘古矿山大模型」-首个能源行业商业大模型" aria-label="Permalink to &quot;山东能源与华为联合发布「盘古矿山大模型」，首个能源行业商业大模型&quot;">​</a></h2><p><strong>山东能源集团、华为公司联合发布盘古矿山大模型</strong>，将解决人工智能在矿山领域落地难的问题，引领矿山AI开发模式从作坊式向工厂式转变，为AI大规模进入矿山打下坚实基础。</p><p>作为AI大模型在能源领域的全球首次商用，山东能源、云鼎科技、华为在前期试点验证AI大模型赋能工业生产领域的基础上，正在开发和实施首批场景应用，<strong>涵盖采煤、掘进、主运、辅运、提升、安监、防冲、洗选、焦化9个专业21个场景应用</strong></p><p><a href="https://mp.weixin.qq.com/s/pLqnqh1lWe2ueiKjyNI4gw" target="_blank" rel="noreferrer">山东能源&amp;华为，全球首个矿山领域商用人工智能大模型发布！ (qq.com)</a></p><h2 id="阅文集团发布「阅文妙笔大模型」-国内第一个网文大模型" tabindex="-1">阅文集团发布「阅文妙笔大模型」，国内第一个网文大模型 <a class="header-anchor" href="#阅文集团发布「阅文妙笔大模型」-国内第一个网文大模型" aria-label="Permalink to &quot;阅文集团发布「阅文妙笔大模型」，国内第一个网文大模型&quot;">​</a></h2><p><a href="https://mp.weixin.qq.com/s/wBoCUSt5NVPxnpCC_hqXbg" target="_blank" rel="noreferrer">AIGC助力！作家创作的“金手指”来了 (qq.com)</a></p><p>7月19日，阅文集团正式发布<strong>国内网络文学行业首个大模型「阅文妙笔</strong>」和基于这一大模型的应用产品「<strong>作家助手妙笔版</strong>」。</p><p>阅文妙笔大模型的知识储备能够覆盖情节内容、角色介绍、作品推荐、行业知识等，并在回答的准确度、全面性、提炼总结等方面表现出色，可以辅助阅文创作者完成创作。</p><p>阅文集团 CEO 兼总裁侯晓楠在致辞中表示，阅文妙笔是国内第一个网文大模型，也是最懂网文的大模型，将来会持续升级</p><h2 id="英特尔推出34个开源ai参考套件-降低部署门槛-加速ai落地" tabindex="-1">英特尔推出34个开源AI参考套件，降低部署门槛，加速AI落地 <a class="header-anchor" href="#英特尔推出34个开源ai参考套件-降低部署门槛-加速ai落地" aria-label="Permalink to &quot;英特尔推出34个开源AI参考套件，降低部署门槛，加速AI落地&quot;">​</a></h2><p><a href="https://www.bakersfield.com/ap/news/intel-accelerates-ai-development-with-reference-kits/article_323634df-e88d-5311-b966-53d5e29b8533.html" target="_blank" rel="noreferrer">www.bakersfield.com</a></p><p>7月24日，英特尔公司向开发者社区发布了34个开源AI参考套件，包含模型代码、训练数据、机器学习流程说明、优化AI的库和oneAPI组件等，帮助开发者和数据科学家更便捷地部署人工智能。</p><p>这些基于oneAPI编程模型和英特尔端到端AI软件组合构建的参考套件，可以简化AI开发流程，提升现有智能解决方案，加速部署。这些预配置套件覆盖众多行业，包括消费品、能源、金融、医疗、制造、零售、电信等。</p><p>相比专有环境的局限，这些AI参考套件可以将解决方案时间从周缩短至天，帮助数据科学家和开发者以更低成本、更快速地训练模型。未来，英特尔将继续根据社区反馈更新维护部分套件</p><h2 id="_2023上半年ai发展突飞猛进-要点与亮点全盘回顾" tabindex="-1">2023上半年AI发展突飞猛进，要点与亮点全盘回顾 <a class="header-anchor" href="#_2023上半年ai发展突飞猛进-要点与亮点全盘回顾" aria-label="Permalink to &quot;2023上半年AI发展突飞猛进，要点与亮点全盘回顾&quot;">​</a></h2><p><a href="https://www.kdnuggets.com/2023/07/first-half-2023-data-science-ai-developments.html" target="_blank" rel="noreferrer">The First Half of 2023: Data Science and AI Developments - KDnuggets</a></p><p>2023年上半年，人工智能领域进展神速，出现了一系列技术突破与重要进展。本文通过回顾半年来AI领域的重要成果，总结了这一时期人工智能发展的主要趋势与特点。</p><blockquote><ol><li><strong>自然语言处理 (Natural Language Processing)</strong> ：OpenAI 的 ChatGPT、Google 的 Bard 等对话机器人的出现，大大推动了自然语言处理技术的发展，新的语言模型不断涌现，语言能力显著提升</li><li><strong>自动机器学习 (AutoML)</strong> ：AutoML 进一步发展，可以自动完成数据预处理、超参数调优等任务，大大节省了数据科学家的时间，提高了工作效率</li><li><strong>生成式AI (Generative AI)</strong> ：基于用户提示，可以生成文本、图像等内容的生成式AI技术进一步成熟，被广泛应用于创作、辅助工作等领域</li><li><strong>深度学习 (Deep Learning)</strong> ：深度学习算法不断改进，在图像分类、目标检测等任务上的性能显著提升，已广泛应用于自动驾驶、医疗等行业</li><li><strong>边缘计算 (Edge Computing)</strong> ：为支持AI技术的计算需求，边缘计算技术进一步发展，使数据处理更实时高效，Google推出了新一代TPU加速芯片</li><li><strong>道德合规 (Ethical AI and Data Science)</strong> ：随着AI应用日益广泛，各国加快出台法规，关注算法歧视、隐私保护等道德风险，推动AI的健康发展</li></ol></blockquote>',31),n=[l];function i(s,h,p,c,u,m){return a(),r("div",null,n)}const _=e(o,[["render",i]]);export{d as __pageData,_ as default};
